def gen(rng, size):
    limit = max(1, min(size, 25))
    # build as nested structure honoring root.val = min(children)
    count = [0]
    def build(val):
        if count[0] >= limit or rng.random() < 0.4:
            count[0] += 1
            return (val, None, None)
        count[0] += 1
        # one child keeps val, the other is >= val
        bigger = val + rng.randint(0, 50)
        if rng.random() < 0.5:
            lv, rv = val, bigger
        else:
            lv, rv = bigger, val
        left = build(lv)
        right = build(rv)
        return (val, left, right)
    root = build(rng.randint(1, 1000))
    out = []
    from collections import deque
    q = deque([root])
    while q:
        node = q.popleft()
        if node is None:
            out.append(None); continue
        v, l, r = node
        out.append(v)
        q.append(l); q.append(r)
    while out and out[-1] is None:
        out.pop()
    return [out]

