class Solution:
    def findSecondMinimumValue(self, root):
        vals = set()
        stack = [root]
        while stack:
            n = stack.pop()
            if not n:
                continue
            vals.add(n.val)
            stack.append(n.left); stack.append(n.right)
        s = sorted(vals)
        return s[1] if len(s) >= 2 else -1

