class Solution:
    def findSecondMinimumValue(self, root):
        first = root.val
        second = float('inf')
        def walk(node):
            nonlocal second
            if not node:
                return
            if first < node.val < second:
                second = node.val
            elif node.val == first:
                walk(node.left); walk(node.right)
        walk(root)
        return second if second != float('inf') else -1

