var findSecondMinimumValue = function(root) {
    const first = root.val;
    let second = Infinity;
    function walk(node) {
        if (!node) return;
        if (node.val > first && node.val < second) {
            second = node.val;
        } else if (node.val === first) {
            walk(node.left); walk(node.right);
        }
    }
    walk(root);
    return second === Infinity ? -1 : second;
};
